        }

        [TestCleanup]
        public void Cleanup()
        {
            _service?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesNotificationWithCorrectProperties()
        {
            // Arrange & Act
            _service.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "Admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("John Doe"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course", notification.EntityType);
            Assert.AreEqual("101", notification.EntityId);
            Assert.AreEqual("UPDATE", notification.Operation);
            Assert.IsTrue(notification.Message.Contains("ID: 101"));
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", "Alice Smith", EntityOperation.CREATE, "Admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student 'Alice Smith' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Department", "5", "English", EntityOperation.DELETE, "Admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Department 'English' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_CreateOperation_GeneratesIdBasedMessage()
        {
            // Arrange & Act
            _service.SendNotification("Instructor", "7", EntityOperation.CREATE, "Admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Instructor (ID: 7) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToNow()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            var after = DateTime.Now.AddSeconds(1);

            // Assert
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _service.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            // Arrange
            _service.SendNotification("Type1", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("Type2", "2", "Second", EntityOperation.UPDATE);
            _service.SendNotification("Type3", "3", "Third", EntityOperation.DELETE);

            // Act & Assert
            var first = _service.ReceiveNotification();
            Assert.AreEqual("Type1", first.EntityType);

            var second = _service.ReceiveNotification();
            Assert.AreEqual("Type2", second.EntityType);

            var third = _service.ReceiveNotification();
            Assert.AreEqual("Type3", third.EntityType);

            var fourth = _service.ReceiveNotification();
            Assert.IsNull(fourth);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op for in-memory, just verify no exception
            _service.MarkAsRead(1);
            _service.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            _service.Dispose();
            // Verify can still be called without error (idempotent)
        }

        [TestMethod]
        public void SendNotification_OverloadWithoutDisplayName_SetsProperties()
        {
            // Arrange & Act
            _service.SendNotification("Instructor", "10", EntityOperation.DELETE, "Teacher");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Instructor", notification.EntityType);
            Assert.AreEqual("10", notification.EntityId);
            Assert.AreEqual("DELETE", notification.Operation);
            Assert.AreEqual("Teacher", notification.CreatedBy);
        }
    }
}

