namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelper
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { FirstMidName = "Alice", LastName = "Smith", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Bob", LastName = "Jones", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { FirstMidName = "Charlie", LastName = "Brown", EnrollmentDate = DateTime.Parse("2020-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context, int? instructorId = null)
        {
            context.Departments.AddRange(
                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructorId },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = null }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context, int departmentId)
        {
