+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using System.Collections.Generic;
+using System.Linq;
+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public sealed class PaginatedListTests
+    {
+        [TestMethod]
+        public void Constructor_WithItems_SetsPageIndexAndTotalPages()
+        {
+            // Arrange
+            var items = new List<int> { 1, 2, 3 };
+
+            // Act
+            var result = new PaginatedList<int>(items, 25, 2, 10);
+
+            // Assert
+            Assert.AreEqual(2, result.PageIndex);
+            Assert.AreEqual(3, result.TotalPages);
+            Assert.AreEqual(3, result.Count);
+            Assert.AreEqual(1, result[0]);
+            Assert.AreEqual(2, result[1]);
+            Assert.AreEqual(3, result[2]);
+        }
+
+        [TestMethod]
+        public void Constructor_WithEmptyItems_SetsZeroCount()
+        {
+            // Arrange & Act
+            var result = new PaginatedList<int>(new List<int>(), 0, 1, 10);
+
+            // Assert
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(1, result.PageIndex);
+            Assert.AreEqual(0, result.TotalPages);
+        }
+
+        [TestMethod]
+        [DataRow(25, 10, 3, DisplayName = "25 items / 10 per page = 3 pages")]
+        [DataRow(20, 10, 2, DisplayName = "20 items / 10 per page = 2 pages")]
+        [DataRow(1, 10, 1, DisplayName = "1 item / 10 per page = 1 page")]
+        [DataRow(10, 10, 1, DisplayName = "10 items / 10 per page = 1 page")]
+        [DataRow(11, 10, 2, DisplayName = "11 items / 10 per page = 2 pages")]
+        public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int totalCount, int pageSize, int expectedTotalPages)
+        {
+            // Act
+            var result = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);
+
+            // Assert
+            Assert.AreEqual(expectedTotalPages, result.TotalPages);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_OnFirstPage_ReturnsFalse()
+        {
+            // Arrange
+            var result = new PaginatedList<int>(new List<int>(), 25, 1, 10);
+
+            // Assert
+            Assert.IsFalse(result.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_OnSecondPage_ReturnsTrue()
+        {
+            // Arrange
+            var result = new PaginatedList<int>(new List<int>(), 25, 2, 10);
+
+            // Assert
+            Assert.IsTrue(result.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_OnLastPage_ReturnsFalse()
+        {
+            // Arrange
+            var result = new PaginatedList<int>(new List<int>(), 25, 3, 10);
+
+            // Assert
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_OnFirstPage_ReturnsTrue()
+        {
+            // Arrange
+            var result = new PaginatedList<int>(new List<int>(), 25, 1, 10);
+
+            // Assert
+            Assert.IsTrue(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_SinglePage_ReturnsFalse()
+        {
+            // Arrange
+            var result = new PaginatedList<int>(new List<int>(), 5, 1, 10);
+
+            // Assert
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_FirstPage_ReturnsCorrectItems()
+        {
+            // Arrange
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            // Act
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            // Assert
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(1, result[0]);
+            Assert.AreEqual(10, result[9]);
+            Assert.AreEqual(1, result.PageIndex);
+            Assert.AreEqual(3, result.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_MiddlePage_ReturnsCorrectItems()
+        {
+            // Arrange
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            // Act
+            var result = PaginatedList<int>.Create(source, 2, 10);
+
+            // Assert
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(11, result[0]);
+            Assert.AreEqual(20, result[9]);
+            Assert.IsTrue(result.HasPreviousPage);
+            Assert.IsTrue(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_LastPage_ReturnsRemainingItems()
+        {
+            // Arrange
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            // Act
+            var result = PaginatedList<int>.Create(source, 3, 10);
+
+            // Assert
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(21, result[0]);
+            Assert.AreEqual(25, result[4]);
+            Assert.IsTrue(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            // Arrange
+            var source = Enumerable.Empty<int>().AsQueryable();
+
+            // Act
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            // Assert
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(0, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_ExactlyOnePage_NoNextOrPrevious()
+        {
+            // Arrange
+            var source = Enumerable.Range(1, 10).AsQueryable();
+
+            // Act
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            // Assert
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+    }
+}
