using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void About_WithStudents_ReturnsViewWithEnrollmentDateGroups()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { FirstMidName = "Alice", LastName = "Smith", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Bob", LastName = "Jones", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Charlie", LastName = "Brown", EnrollmentDate = DateTime.Parse("2021-09-01") }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);

            var group2020 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2020-09-01"));
            Assert.AreEqual(2, group2020.StudentCount);

            var group2021 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2021-09-01"));
            Assert.AreEqual(1, group2021.StudentCount);
        }

        [TestMethod]
        public void About_NoStudents_ReturnsEmptyList()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            // Act
            var result = _controller.Contact() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            // Act
            var result = _controller.Error();

            // Assert
            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            // Act
            var result = _controller.Unauthorized() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _envMock;
        private Mock<ILogger<CoursesController>> _loggerMock;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _envMock = new Mock<IWebHostEnvironment>();
            _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
            _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        private void SeedCoursesWithDepartment()
        {
            var dept = new Department { Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            _context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID }
            );
            _context.SaveChanges();
        }

        [TestMethod]
        public void Index_ReturnsViewWithCoursesList()
        {
            // Arrange
            SeedCoursesWithDepartment();

            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
