using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            // Drain the static notification queue
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            svc.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);

            var value = result.Value;
            Assert.IsNotNull(value);
            // Check the anonymous type properties via reflection
            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            Assert.AreEqual(0, countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_WithMessages_ReturnsNotifications()
        {
            // Arrange - Send notifications using the controller's notificationService (via BaseController)
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Alice Smith", EntityOperation.CREATE, "Admin");
            svc.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Admin");

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(value);
            Assert.IsTrue(count >= 2, $"Expected at least 2 notifications, got {count}");

            svc.Dispose();
        }

        [TestMethod]
        public void MarkAsRead_ValidId_ReturnsSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(value));
        }

        [TestMethod]
        public void MarkAsRead_InvalidId_StillReturnsSuccess()
        {
            // MarkAsRead is a no-op for in-memory, so any ID should succeed
            // Act
            var result = _controller.MarkAsRead(9999);

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_LimitsToTenNotifications()
        {
            // Arrange - Send more than 10 notifications
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Student", i.ToString(), $"Student {i}", EntityOperation.CREATE, "Admin");
            }

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(value);
            Assert.AreEqual(10, count, "Should limit to 10 notifications");

            // Clean up remaining notifications
            while (svc.ReceiveNotification() != null) { }
            svc.Dispose();
        }
    }
}

